            _ = SelectListItemByText(root, "\uAC1D\uCCB4 \uD0D0\uC9C0");

            int cardsFound = 0;
            int cardsVerified = 0;
            double totalMilliseconds = 0D;
            double maxMilliseconds = 0D;
