                || args.PropertyName == nameof(viewModel.RobotPos)
                || args.PropertyName == nameof(viewModel.ImagePos)
                || args.PropertyName == nameof(viewModel.PixelColor)
                || args.PropertyName == nameof(viewModel.HeightValue))
