        AssertNamedXamlBinding(statusXaml, xName, "WorkflowProgressText", "Text", "WorkflowProgressText");
        AssertNamedXamlBinding(statusXaml, xName, "WorkflowNextActionText", "Text", "WorkflowNextActionText");
