        AssertNamedXamlBinding(xaml, xName, "FocusCurrentLabelButton", "IsEnabled", "IsFocusCurrentLabelEnabled");
        AssertNamedXamlBinding(xaml, xName, "FocusCurrentLabelButton", "ToolTip", "FocusCurrentLabelToolTip");
